  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Forbidden' });
    req.user = user;
    next();
  });
};

app.get('/users', authenticateToken, (req, res) => { ... });
```

#### 2. No HTTPS/TLS ‚ÄĒ `A02: Cryptographic Failures` (CWE-295)
All traffic is plaintext, enabling MITM attacks, session hijacking, and credential theft.

**Fix:**
```js
const https = require('https');
const fs = require('fs');
https.createServer({
  key: fs.readFileSync('private-key.pem'),
  cert: fs.readFileSync('certificate.pem')
}, app).listen(443);
```

#### 3. No Session Management ‚ÄĒ `A07: Identification & Authentication Failures` (CWE-384)
No concept of user identity, no audit trail, no secure logout possible.

**Fix:**
```js
const session = require('express-session');
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true, httpOnly: true, sameSite: 'strict', maxAge: 3600000 }
}));
```

---

### ūüü† HIGH

#### 4. Sensitive Data Exposure (Emails Hardcoded) ‚ÄĒ `A02` (CWE-200)
Real email addresses are hardcoded in source and returned in every response. GDPR/CCPA risk.

**Fix:** Return only the minimum necessary fields; pull data from a database with proper access controls ‚ÄĒ never hardcode PII.

#### 5. No Rate Limiting ‚ÄĒ `A05: Security Misconfiguration` (CWE-770)
No throttling allows brute force, DoS, and enumeration attacks.

**Fix:**
```js
const rateLimit = require('express-rate-limit');
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));
```

#### 6. No Security Headers ‚ÄĒ `A08: Software & Data Integrity Failures` (CWE-693)
Missing `Content-Security-Policy`, `X-Frame-Options`, `Strict-Transport-Security`, etc.

**Fix:**
```js
const helmet = require('helmet');
app.use(helmet());
```

#### 7. No Request Logging or Monitoring ‚ÄĒ `A09: Logging & Monitoring Failures` (CWE-532)
No visibility into traffic, errors, or attacks. Incidents cannot be detected or investigated.

**Fix:**
```js
const morgan = require('morgan');
app.use(morgan('combined', { stream: fs.createWriteStream('access.log', { flags: 'a' }) }));
```

#### 8. No Input Validation ‚ÄĒ `A03: Injection` (CWE-20)
No validation framework in place. Any future query parameters or request bodies are injectable.

**Fix:**
```js
const { query, validationResult } = require('express-validator');
app.get('/users', query('id').isInt({ min: 1 }).optional(), (req, res) => {
  const errors = validationResult(req);
